package demo;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.web.client.RestTemplateBuilder;
import org.springframework.http.HttpMethod;
import org.springframework.stereotype.Service;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestClientResponseException;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.util.Map;


@RestController
public class MainController {
    @Value("${auth.base}") private String base;

    public static void main(String[] args) throws Exception {
        RestTemplate rest = new RestTemplateBuilder()
                .basicAuthentication("clientId", "secret")
                .build();

        URI uri = new URI(base + "/user");
        try {
            Map response = (Map) rest.exchange(uri, HttpMethod.GET).getBody();
            System.out.println(response);
        } catch (RestClientResponseException e) {
            if (e.getRawStatusCode() == 401 ||
                    e.getRawStatusCode() == 403)
                System.err.println("Unauthenticated");
        }
    }
}